import type { ArtifactOutputItem } from '@coral/shared/protocol/local-agent/core'
import type { ArtifactExtractRule, ToolCallBlock } from './types'
import { commandIncludes, parseJsonFromOutput, resolveOutputText } from './utils'

export const pingcodeWorkItemRule: ArtifactExtractRule = {
  id: 'pingcode-workitem',
  match(tc: ToolCallBlock): boolean {
    return (
      tc.kind === 'execute' &&
      tc.status === 'completed' &&
      commandIncludes(tc.rawInput, 'create_work_item')
    )
  },
  extract(tc: ToolCallBlock): ArtifactOutputItem[] {
    const outputText = resolveOutputText(tc.rawOutput)
    if (!outputText) return []
    const parsed = parseJsonFromOutput(outputText) as {
      success?: boolean
      data?: {
        resultType?: string
        workItemReadableResp?: {
          url?: string
          readableMap?: { 标题?: string; 工作项类型?: string }
        }
      }
    } | null
    if (!parsed?.success || parsed.data?.resultType !== 'SUCCESS') return []
    const resp = parsed.data?.workItemReadableResp
    if (!resp?.url) return []
    const itemType = resp.readableMap?.工作项类型 || '工作项'
    const title = resp.readableMap?.标题 || itemType
    return [
      {
        type: 'link',
        url: resp.url,
        title,
        kind: 'new',
        icon: 'https://picasso-static.xiaohongshu.com/fe-platform/01c85764aae2dbee011a60ba83f67bb7df193773.png',
        subtitle: `PingCode ${itemType}`,
      },
    ]
  },
}

